exercises.solution_code:
#include <iostream>

struct Rectangle {
    int width{};
    int height{};

    int area() const      { return width * height; }
    int perimeter() const { return 2 * (width + height); }
};

int main() {
    int n;
    std::cin >> n;

    for (int i = 0; i < n; ++i) {
        int w, h;
        std::cin >> w >> h;

        Rectangle r{w, h};
        std::cout << r.width << " x " << r.height
                  << " -> Area: " << r.area()
                  << ", Perimeter: " << r.perimeter() << '\n';
    }

    return 0;
}
